% Allocate a fluid binding to hold the default LaTeX preamble,
% e.g. for loading tikz packages.
\alloc\base/tex-preamble

\def\texfig[body]{
 \scope{
  % Install a LaTeX preamble to be used by default if none is set.
  \put?\base/tex-preamble{
   % Some useful things from my own library.
   \latex-preamble/string-diagrams
   \latex-preamble/diagrams
  }

  % Wrap the diagram in a figure
  \figure{
   % Render the LaTeX code with the current preamble
   \tex{\get\base/tex-preamble}{\body}
  }
 }
}

\def\my-object{
  \object[self]{
    [method1]{
      the implementation of this method
    }
    [method2]{
      the implementation of another method
      \self#method1
    }
  }
}

{
 inputs = {
   forester = {
     url = "sourcehut:~jonsterling/ocaml-forester";
   };
   flake-utils.url = "github:numtide/flake-utils";
 };
 outputs =
   { self
   , flake-utils
   , nixpkgs
   , forester
   }:
   flake-utils.lib.eachDefaultSystem
     (system:
     let
       pkgs = import nixpkgs { inherit system; };
       legacyPackages = import forester.legacyPackages.${system};
     in
     {
       devShell =
         pkgs.mkShell {
           buildInputs = with pkgs; [
             forester.packages.${system}.default
             texlive.combined.scheme-full
             fswatch
           ];
         };
     });
}

fr:ol.fr:li:
for each {x}\xrightarrow {{f}}{y} and {y}\xrightarrow {{g}}{z} in B and objects \bar {x}\in  E_{x}, \bar {y}\in  E_{y}, \bar {z}\in  E_{z}, a function

     \mathbf {hom}_{E_{f}}{\mathopen {}\left (\bar {x},\bar {y}\right )\mathclose {}} \times \mathbf {hom}_{E_{g}}{\mathopen {}\left (\bar {y},\bar {z}\right )\mathclose {}} \to  \mathbf {hom}_{E_{f;g}}{\mathopen {}\left (\bar {x},\bar {z}\right )\mathclose {}}     

    that we will denote like ordinary (diagrammatic) function composition,

such that the following equations hold:

              1_{\bar {x}};\bar {h} = \bar {h}\qquad      \bar {h};1_{\bar {y}} = \bar {h}\qquad      \bar {f};(\bar {g};\bar {h}) = (\bar {f};\bar {g});\bar {h}     


    Note that these are well-defined because of the corresponding laws for the base category B.
